import RegularEvent from"@typo3/core/event/regular-event.js";import Notification from"@typo3/backend/notification.js";import Modal from"@typo3/backend/modal.js";import Severity from"@typo3/backend/severity.js";new RegularEvent("click",(e,t)=>{e.preventDefault();const o=t.closest("tr").querySelector(".col-title").textContent.trim();fetch(t.getAttribute("href")).then(()=>{Notification.success("Logout",'User "'+o+'" has been logged out successfully'),location.reload()})}).delegateTo(document,".logoutUser"),new RegularEvent("click",(e,t)=>{e.preventDefault();const o=t.closest("tr").querySelector(".col-title").textContent.trim();Modal.confirm(t.dataset.title,t.dataset.content,Severity.error).addEventListener("button.clicked",e=>{"ok"===e.target.getAttribute("name")&&fetch(t.getAttribute("href")).then(()=>{Notification.success("Delete",'User "'+o+'" has been deleted successfully'),location.reload()}),Modal.dismiss()})}).delegateTo(document,".deleteUser");